Schema::create('branches', function (Blueprint $t) {
    $t->string('id', 64)->primary();  // brn_<ulid>

    $t->workspaceable();              // Workspaces — workspace_id + FK + composite index
    $t->applicable();              // Workspaces — application_id + FK (boundary rows only)

    $t->string('name');
    $t->text('description')->nullable();

    $t->systemFlag();              // Foundation
    $t->metadata();                // Foundation
    $t->userstampable();           // Foundation
    $t->auditable();               // Foundation (marker — no column)
    $t->versionable();             // Foundation (marker — versions table owned by mpociot/versionable)
    $t->sluggable('name');         // Foundation — slug + unique index scoped to (workspace_id, slug)
    $t->filterable();              // Foundation (marker)
    $t->sortable();                // Foundation — sort_order + composite index

    // Import / export / search markers no longer live in the schema — the transfer
    // and search modules discover their models via attribute-driven registration
    // (#[Importable] / #[Exportable] / #[Searchable] on the model class), not
    // via migration macros.

    $t->softDeletes();
    $t->timestamps();
});
